  var _id = 0;
  function uid(prefix) { return (prefix || 'gdev') + '-' + (++_id); }

  function sc(value, thresholds) {
    if (value >= thresholds[0]) return 'score-good';
    if (value >= thresholds[1]) return 'score-warning';
    return 'score-critical';
  }

  function tog(id) {
    var body = document.getElementById(id);
    var ch = document.getElementById(id + '-ch');
    if (!body) return;
    var isOpen = body.classList.toggle('open');
    if (ch) ch.classList.toggle('open', isOpen);
  }

  function toggleTheme() {
    document.documentElement.classList.toggle('light-theme');
  }

  function printReport() {
    var wasLight = document.documentElement.classList.contains('light-theme');
    var allBodies = document.querySelectorAll('.block-body');
    var states = [];
    document.documentElement.classList.add('light-theme');
    allBodies.forEach(function(b) { states.push(b.classList.contains('open')); b.classList.add('open'); });
    setTimeout(function() {
      window.print();
      setTimeout(function() {
        if (!wasLight) document.documentElement.classList.remove('light-theme');
        allBodies.forEach(function(b, i) { if (!states[i]) b.classList.remove('open'); });
      }, 300);
    }, 100);
  }

